/**
 * Generador lista Grupo DISCO desde simulacion verificada
 * Formato multi-hoja: AVANTI PASTAS Y SALSAS, PASTAMANIA, CONGELADOS AVANTI
 */
import ExcelJS from 'exceljs'

interface Item {
  ean: string
  cod_interno: string | number
  cod_cadena: string | number
  descripcion: string
  familia: string
  sub_familia: string
  marca: string
  unidades_caja: string | number
  iva_rate: number
  precio_neto: number
  precio_c_iva: number
  pvp_sugerido: number
  precio_neto_anterior: number | null
  precio_c_iva_anterior: number | null
  pvp_anterior: number | null
  aumento_pct: number | null
}

interface Params {
  items: Item[]
  cadena: string
  vigencia: string
  nombre: string | null
}

// ── Colores ──────────────────────────────────────────────────────────────────
const RED   = 'FFCC0000'
const WHITE = 'FFFFFFFF'
const LRED  = 'FFFFEBEE'
const BLUE  = 'FF0D47A1'
const LBLUE = 'FFE3F2FD'
const GRAY  = 'FF757575'

// ── Logos embebidos (base64 PNG) ─────────────────────────────────────────────
const AVANTI_LOGO_B64 = ''
const PASTAMANIA_LOGO_B64 = ''

// ── Helpers ──────────────────────────────────────────────────────────────────
function isPastamania(marca: string): boolean {
  return marca === 'PASTAMANIA' || marca === 'PASTAMANÍA'
}

function isTataPropia(marca: string): boolean {
  return ['TA-TA', 'QUE TAPA'].includes(marca)
}

function isMarcaPrivadaTata(marca: string): boolean {
  return ['QUE FACIL', 'TUTTI PASTA'].includes(marca)
}

// Mapeo sub_familia → grupo visual para Masas AVANTI
function getMasasGroup(item: Item): string {
  if (item.descripcion.toLowerCase().includes('light')) return 'Masas Light'
  const sf = item.sub_familia
  if (['Copetin', 'Empanadas x 12', 'Empanadas x 20', 'Empanadas x 40', 'Empanadas XL', 'Empanadas x 6'].includes(sf)) {
    return 'Masas para Empanadas'
  }
  if (['Tapas Rectangulares', 'Tapas Redondas'].includes(sf)) return 'Masas para Tapas'
  if (sf === 'Masa Tarta') return 'Masas para Tartas'
  return 'Masas para Empanadas'
}

// Orden canónico de sub_familia dentro de cada grupo
const SF_ORDER = [
  'Copetin', 'Empanadas x 12', 'Empanadas x 20', 'Empanadas x 40', 'Empanadas XL', 'Empanadas x 6',
  'Tapas Redondas', 'Tapas Rectangulares', 'Masa Tarta',
  'Ravioles', 'Raviolones', 'Sorrentinos', 'Tallarines', 'Tagliatelle',
  'Pack Ravioles',
]
function sfRank(sf: string) {
  const i = SF_ORDER.indexOf(sf)
  return i === -1 ? 99 : i
}

// ── Definición de hojas ──────────────────────────────────────────────────────
interface SheetDef {
  name: string
  filter: (i: Item, cadena?: string) => boolean
  getGroup: (i: Item) => string
  groupOrder: string[] | null
  accent: string
  pvpFill: string
  footer: string | null
}

const SHEET_DEFS: SheetDef[] = [
  {
    name: 'AVANTI',
    filter: (i) => i.familia === 'Masas' && !isPastamania(i.marca) && !isTataPropia(i.marca) && !isMarcaPrivadaTata(i.marca),
    getGroup: getMasasGroup,
    groupOrder: ['Masas para Empanadas', 'Masas para Tapas', 'Masas para Tartas', 'Masas Light'],
    accent: RED,
    pvpFill: LRED,
    footer: '* A los precios de las Tapas y Masa para Tartas se le aplicara en factura un 25% de descuento en general.',
  },
  {
    name: 'AVANTI PASTAS Y SALSAS',
    filter: (i) =>
      (i.familia === 'Pastas Frescas ATM' &&
        ['Sorrentinos', 'Tallarines', 'Tagliatelle', 'Ravioles'].includes(i.sub_familia) &&
        !isPastamania(i.marca) && !isTataPropia(i.marca) && !isMarcaPrivadaTata(i.marca))
      || (i.familia === 'Salsas' && !isPastamania(i.marca) && !isTataPropia(i.marca) && !isMarcaPrivadaTata(i.marca)),
    getGroup: (i) => i.familia === 'Salsas' ? 'Salsas' : 'Pasta Fresca Envasada',
    groupOrder: ['Pasta Fresca Envasada', 'Salsas'],
    accent: RED,
    pvpFill: LRED,
    footer: null,
  },
  {
    name: 'PASTAMANIA',
    filter: (i, cadena) => {
      const isTata = cadena?.toUpperCase() === 'TATA'
      // Tallarines van a la hoja QUE TAPA / PASTAMANÍA en cadenas no-TATA
      if (!isTata && i.sub_familia === 'Tallarines' && isPastamania(i.marca)) return false
      return (i.familia === 'Masas' && isPastamania(i.marca))
        || i.sub_familia === 'Pack Ravioles'
        || (i.familia === 'Pastas Frescas ATM' && i.sub_familia === 'Tallarines' && isPastamania(i.marca))
    },
    getGroup: (i) => {
      if (i.sub_familia === 'Pack Ravioles' || i.sub_familia === 'Tallarines') return 'Pasta Fresca Envasada'
      return getMasasGroup(i)
    },
    groupOrder: ['Masas para Empanadas', 'Masas para Tapas', 'Pasta Fresca Envasada'],
    accent: BLUE,
    pvpFill: LBLUE,
    footer: '* A los precios de las Tapas se le aplicara en Factura un Descuento de 25%.',
  },
  {
    name: 'QUE TAPA - PASTAMANIA',
    filter: (i, cadena) => {
      if (cadena?.toUpperCase() === 'TATA') return false
      return i.marca === 'QUE TAPA'
        || (isPastamania(i.marca) && i.sub_familia === 'Tallarines')
    },
    getGroup: (i) => i.familia === 'Masas' ? getMasasGroup(i) : 'Pasta Fresca Envasada',
    groupOrder: ['Masas para Tapas', 'Pasta Fresca Envasada'],
    accent: BLUE,
    pvpFill: LBLUE,
    footer: '* A los precios de las Tapas se le aplicara en Factura un Descuento de 25%.',
  },
  {
    name: 'CONGELADOS AVANTI',
    filter: (i) => ['Empanadas Congeladas', 'Pizzas Congeladas', 'Pastas Congeladas'].includes(i.familia),
    getGroup: (i) => i.familia,
    groupOrder: ['Empanadas Congeladas', 'Pastas Congeladas', 'Pizzas Congeladas'],
    accent: RED,
    pvpFill: LRED,
    footer: null,
  },
  {
    name: 'TA-TA',
    filter: (i, cadena) => isTataPropia(i.marca) && cadena?.toUpperCase() === 'TATA',
    getGroup: (i) => i.familia === 'Masas' ? getMasasGroup(i) : 'Pastas Frescas',
    groupOrder: ['Masas para Empanadas', 'Masas para Tapas', 'Masas para Tartas', 'Masas Light', 'Pastas Frescas'],
    accent: 'FFE65100',   // naranja
    pvpFill: 'FFFBE9E7',  // naranja claro
    footer: null,
  },
  {
    name: 'TUTTI PASTA - QUE FACIL',
    filter: (i, cadena) => isMarcaPrivadaTata(i.marca) && cadena?.toUpperCase() === 'TATA',
    getGroup: (i) => i.familia === 'Masas' ? getMasasGroup(i) : 'Pastas Frescas',
    groupOrder: ['Masas para Empanadas', 'Pastas Frescas'],
    accent: 'FF2E7D32',   // verde
    pvpFill: 'FFE8F5E9',  // verde claro
    footer: null,
  },
]

// ── Helpers de estilo ────────────────────────────────────────────────────────
function headerStyle(cell: ExcelJS.Cell, bg = RED) {
  cell.fill      = { type: 'pattern', pattern: 'solid', fgColor: { argb: bg } }
  cell.font      = { bold: true, color: { argb: WHITE }, size: 8, name: 'Arial' }
  cell.alignment = { horizontal: 'center', vertical: 'middle', wrapText: true }
  cell.border    = { bottom: { style: 'thin' }, right: { style: 'thin', color: { argb: 'FFDDDDDD' } } }
}

function groupHeaderStyle(cell: ExcelJS.Cell, accent = RED) {
  cell.fill      = { type: 'pattern', pattern: 'solid', fgColor: { argb: accent } }
  cell.font      = { bold: true, size: 9, name: 'Arial', color: { argb: WHITE } }
  cell.alignment = { horizontal: 'left', vertical: 'middle', indent: 1 }
}

function numberCell(cell: ExcelJS.Cell, value: number | null, fmt = '"$"#,##0.00') {
  if (value === null || value === undefined) {
    cell.value = null
  } else {
    cell.value = value
    cell.numFmt = fmt
  }
  cell.font      = { size: 8, name: 'Arial' }
  cell.alignment = { horizontal: 'right' }
}

function addColHeaders(ws: ExcelJS.Worksheet, row: number, ivaLabel: string, accent = RED, codLabel = 'COD\nGRUPO DISCO') {
  const cols = [
    'COD. BARRAS', 'COD.\nINTERNO', codLabel, 'DESCRIPCION',
    'UNIDADES\nPAQ / CAJA',
    'PRECIOS\nSIN IVA', `PRECIO FACT\nIVA ${ivaLabel} INC`, 'PVP\nSUGERIDO', 'AUMENTO',
    '', '',
    'PRECIOS\nSIN IVA', `PRECIO FACT\nIVA ${ivaLabel} INC`, 'AUMENTO',
  ]
  const r = ws.getRow(row)
  r.height = 30
  cols.forEach((v, ci) => {
    const cell = r.getCell(ci + 1)
    cell.value = v
    if (ci === 9 || ci === 10) {
      // Columnas J y K sin estilo
      cell.value = null
    } else {
      headerStyle(cell, ci >= 11 ? GRAY : accent)
    }
  })
}

function buildSheet(
  wb: ExcelJS.Workbook,
  def: SheetDef,
  sheetItems: Item[],
  cadena: string,
  fechaVig: string,
  nombre: string | null,
  showCodGrupo = true,
): void {
  if (sheetItems.length === 0) return

  const ws = wb.addWorksheet(def.name)
  ws.columns = [
    { width: 18 },  // A: COD BARRAS
    { width: 10 },  // B: COD INTERNO
    { width: 13 },  // C: COD GRUPO DISCO
    { width: 46 },  // D: DESCRIPCION
    { width: 14 },  // E: UN/CAJA
    { width: 14 },  // F: PRECIO NETO
    { width: 16 },  // G: PRECIO C IVA
    { width: 13 },  // H: PVP SUGERIDO
    { width: 10 },  // I: AUMENTO
    { width: 2  },  // J: spacer (sin estilo)
    { width: 2  },  // K: spacer (sin estilo)
    { width: 14 },  // L: PRECIO NETO ANT
    { width: 16 },  // M: PRECIO C IVA ANT
    { width: 10 },  // N: AUMENTO ANT
  ]

  if (!showCodGrupo) {
    ws.getColumn(3).hidden = true
  }

  // ── Fila 1: banner (color según identidad de la hoja) ─────────────────────
  ws.getRow(1).height = 52
  ws.mergeCells('A1:I1')
  const bannerCell = ws.getCell('A1')
  bannerCell.fill      = { type: 'pattern', pattern: 'solid', fgColor: { argb: def.accent } }
  bannerCell.alignment = { horizontal: 'center', vertical: 'middle' }
  const listaNombre = nombre ? `  -  ${nombre}` : ''
  bannerCell.value = `LISTA DE PRECIOS ${cadena}${listaNombre}  |  Vigencia: ${fechaVig}`
  bannerCell.font  = { bold: true, size: 13, name: 'Arial', color: { argb: WHITE } }

  // ── Fila 2: barra secundaria ───────────────────────────────────────────────
  ws.getRow(2).height = 16
  for (let c = 1; c <= 11; c++) {
    ws.getRow(2).getCell(c).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: def.accent } }
  }
  ws.mergeCells('L2:N2')
  const prevCell = ws.getCell('L2')
  prevCell.value     = 'PRECIOS ANTERIORES'
  prevCell.font      = { bold: true, size: 8, name: 'Arial', color: { argb: WHITE } }
  prevCell.alignment = { horizontal: 'center', vertical: 'middle' }
  prevCell.fill      = { type: 'pattern', pattern: 'solid', fgColor: { argb: GRAY } }

  let currentRow = 3

  // ── Agrupar y ordenar ─────────────────────────────────────────────────────
  const porGrupo: Record<string, Item[]> = {}
  for (const item of sheetItems) {
    const g = def.getGroup(item)
    if (!porGrupo[g]) porGrupo[g] = []
    porGrupo[g].push(item)
  }

  let grupos: string[]
  if (def.groupOrder) {
    const defined = def.groupOrder.filter(g => porGrupo[g])
    const rest = Object.keys(porGrupo).filter(g => !def.groupOrder!.includes(g)).sort()
    grupos = [...defined, ...rest]
  } else {
    grupos = Object.keys(porGrupo).sort()
  }

  for (const grupo of grupos) {
    const groupItems = porGrupo[grupo]
    if (!groupItems?.length) continue

    const ivaLabel = groupItems[0]?.iva_rate === 0.10 ? '10%' : '22%'

    // Sub-cabecera del grupo
    ws.mergeCells(`A${currentRow}:I${currentRow}`)
    const sfCell = ws.getCell(`A${currentRow}`)
    sfCell.value = grupo
    groupHeaderStyle(sfCell, def.accent)
    ws.getRow(currentRow).height = 18
    currentRow++

    addColHeaders(ws, currentRow, ivaLabel, def.accent, showCodGrupo ? 'COD\nGRUPO DISCO' : 'COD\nTa-Ta')
    currentRow++

    // Ordenar por sub_familia primero, luego por descripcion
    groupItems
      .sort((a, b) => {
        const sfDiff = sfRank(a.sub_familia) - sfRank(b.sub_familia)
        if (sfDiff !== 0) return sfDiff
        return a.descripcion.localeCompare(b.descripcion)
      })
      .forEach((item, idx) => {
        const r = ws.getRow(currentRow)
        r.height = 18

        const bgFill: ExcelJS.Fill = {
          type: 'pattern', pattern: 'solid',
          fgColor: { argb: idx % 2 === 0 ? 'FFFAFAFA' : WHITE },
        }
        const font: Partial<ExcelJS.Font> = { size: 8, name: 'Arial' }

        const eanCell = r.getCell(1)
        eanCell.value  = String(item.ean)
        eanCell.numFmt = '@'
        eanCell.font   = font
        eanCell.fill   = bgFill

        const codCell = r.getCell(2)
        codCell.value     = item.cod_interno ? String(item.cod_interno) : ''
        codCell.numFmt    = '@'
        codCell.font      = font
        codCell.fill      = bgFill
        codCell.alignment = { horizontal: 'center' }

        const codGrupoCell = r.getCell(3)
        codGrupoCell.value     = item.cod_cadena ? String(item.cod_cadena) : ''
        codGrupoCell.numFmt    = '@'
        codGrupoCell.font      = font
        codGrupoCell.fill      = bgFill
        codGrupoCell.alignment = { horizontal: 'center' }

        const descCell = r.getCell(4)
        descCell.value = item.descripcion
        descCell.font  = font
        descCell.fill  = bgFill

        const udsCell = r.getCell(5)
        udsCell.value     = item.unidades_caja ? String(item.unidades_caja) : ''
        udsCell.font      = font
        udsCell.fill      = bgFill
        udsCell.alignment = { horizontal: 'center' }

        numberCell(r.getCell(6), item.precio_neto)
        r.getCell(6).fill = bgFill

        numberCell(r.getCell(7), item.precio_c_iva)
        r.getCell(7).fill = bgFill

        numberCell(r.getCell(8), item.pvp_sugerido)
        r.getCell(8).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: def.pvpFill } }
        r.getCell(8).font = { ...font, bold: true }

        const aumCell = r.getCell(9)
        if (item.aumento_pct !== null) {
          aumCell.value  = item.aumento_pct
          aumCell.numFmt = '0.0%'
          aumCell.font   = { ...font, color: { argb: item.aumento_pct > 0 ? 'FF1B5E20' : 'FFC62828' } }
        }
        aumCell.fill      = bgFill
        aumCell.alignment = { horizontal: 'center' }

        // Columnas J y K: sin fondo, sin bordes
        r.getCell(10).value = null
        r.getCell(11).value = null

        numberCell(r.getCell(12), item.precio_neto_anterior)
        r.getCell(12).fill = bgFill

        numberCell(r.getCell(13), item.precio_c_iva_anterior)
        r.getCell(13).fill = bgFill

        const aumAntCell = r.getCell(14)
        if (item.aumento_pct !== null) {
          aumAntCell.value  = item.aumento_pct
          aumAntCell.numFmt = '0.0%'
          aumAntCell.font   = font
        }
        aumAntCell.fill      = bgFill
        aumAntCell.alignment = { horizontal: 'center' }

        currentRow++
      })

    currentRow++ // fila en blanco entre grupos
  }

  // ── Footer ────────────────────────────────────────────────────────────────
  if (def.footer && cadena.toUpperCase() !== 'TATA') {
    currentRow++
    ws.mergeCells(`A${currentRow}:I${currentRow}`)
    const footerCell = ws.getCell(`A${currentRow}`)
    footerCell.value     = def.footer
    footerCell.font      = { italic: true, size: 8, name: 'Arial', color: { argb: RED } }
    footerCell.alignment = { horizontal: 'left', vertical: 'middle', indent: 1 }
    ws.getRow(currentRow).height = 16
  }
}

// ── Función principal exportada ──────────────────────────────────────────────
export async function generarDiscoXlsx({ items, cadena, vigencia, nombre }: Params): Promise<Buffer> {
  const wb = new ExcelJS.Workbook()
  wb.creator = 'Avanti Uruguay'
  wb.created = new Date()

  // Los logos se agregan al workbook una sola vez aunque no se usen en cada hoja
  // (eliminados del layout por pedido del usuario — solo se conservan las constantes)
  void AVANTI_LOGO_B64
  void PASTAMANIA_LOGO_B64

  const fechaVig = vigencia
    ? new Date(vigencia + 'T00:00:00').toLocaleDateString('es-UY', { day: '2-digit', month: '2-digit', year: 'numeric' })
    : ''
  const showCodGrupo = cadena.toUpperCase() !== 'TATA'
  for (const def of SHEET_DEFS) {
    const sheetItems = items.filter(i => def.filter(i, cadena))
    buildSheet(wb, def, sheetItems, cadena, fechaVig, nombre, showCodGrupo)
  }

  return wb.xlsx.writeBuffer() as unknown as Promise<Buffer>
}
